import React, { useState } from 'react';
import { AtSign, Lock, User } from 'lucide-react';

export default function CustomerAuthCard({ onSubmit, isLoading }) {
  const [form, setForm] = useState({ email: '', password: '' });

  const handleChange = (e) => setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(form);
  };

  return (
    <div className="card shadow border-0 h-100">
      <div className="card-body p-4">
        <div className="text-center mb-4">
          <User size={32} className="text-danger mb-2" />
          <h3 className="h5">Customer Login</h3>
          <p className="text-muted small">Track bookings, request pickup, download receipts.</p>
        </div>
        <form onSubmit={handleSubmit}>
          <label className="form-label">Email</label>
          <div className="input-group mb-3">
            <span className="input-group-text">
              <AtSign size={16} />
            </span>
            <input
              type="email"
              name="email"
              className="form-control"
              placeholder="you@example.com"
              value={form.email}
              onChange={handleChange}
              required
            />
          </div>
          <label className="form-label">Password</label>
          <div className="input-group mb-4">
            <span className="input-group-text">
              <Lock size={16} />
            </span>
            <input
              type="password"
              name="password"
              className="form-control"
              placeholder="••••••••"
              value={form.password}
              onChange={handleChange}
              required
            />
          </div>
          <button className="btn btn-danger w-100" disabled={isLoading}>
            {isLoading ? 'Signing in...' : 'Login as Customer'}
          </button>
        </form>
      </div>
    </div>
  );
}
